CREATE TABLE risk_profile(id BIGINT PRIMARY KEY AUTO_INCREMENT,reviewer_id VARCHAR(64) NOT NULL,window_start TIMESTAMP(6) NOT NULL,reviewed BIGINT NOT NULL DEFAULT 0,correct_count BIGINT NOT NULL DEFAULT 0,total_duration_ms BIGINT NOT NULL DEFAULT 0,error_counts_json JSON NOT NULL,level VARCHAR(32) NOT NULL,training_required BOOLEAN NOT NULL DEFAULT FALSE,version BIGINT NOT NULL DEFAULT 0,UNIQUE KEY uk_reviewer_window(reviewer_id,window_start));
